fn spawn_icon_worker(     runtime_services: &RuntimeServices,     mut rx: WorkerRx<IconRequest>,     tx: WorkerTx<IconResult>, ) {     runtime_services.spawn(async move {         while let Some(request) = rx.recv().await {             let Some(bytes) = game_icon_bytes(&request.game_id) else {                 continue;             };             let Some(image) = load_icon_color_image(bytes) else {                 continue;             };             let _ = tx.send(IconResult {                 game_id: request.game_id,                 image,             });         }     }); }  fn spawn_gif_preview_worker(     runtime_services: &RuntimeServices,     mut rx: WorkerRx<GifPreviewRequest>,     tx: WorkerTx<GifPreviewEvent>, ) {     let client = runtime_services.http_client.clone();     let handle = runtime_services.handle();     let limiter = Arc::clone(&runtime_services.full_decode_limiter);      runtime_services.spawn(async move {         while let Some(request) = rx.recv().await {             let client = client.clone();             let handle = handle.clone();             let tx = tx.clone();             let limiter = limiter.clone();             tokio::spawn(async move {                 let (out_png, gif_dest, res) = match &request {                     GifPreviewRequest::FromFile { src_path, out_png, gif_dest } => {                         let bytes_res = tokio::fs::read(&src_path).await.map_err(|err| {                             anyhow!("failed to read gif file {}: {err}", src_path.display())                         });                         (out_png.clone(), gif_dest.clone(), bytes_res)                     }                     GifPreviewRequest::FromUrl { url, out_png, gif_dest } => {                         let cache_path = gif_anim_cache_path(url);                         let bytes_res = async {                             if cache_path.exists() {                                 tokio::fs::read(&cache_path).await.map_err(|e| anyhow::anyhow!(e))                             } else {                                 let mut retries = 0u32;                                 let max_retries = 3u32;                                 loop {                                     let result = async {                                         let resp = client.get(url.clone()).send().await?.error_for_status()?;                                         let bytes = resp.bytes().await?.to_vec();                                         let _ = persistence::write_atomic_bytes(&cache_path, &bytes);                                         Ok::<Vec<u8>, anyhow::Error>(bytes)                                     }.await;                                      match result {                                         Ok(b) => return Ok(b),                                         Err(e) if retries < max_retries => {                                             retries += 1;                                             let backoff_ms = 100 * (2_u64.pow(retries - 1));                                             tokio::time::sleep(std::time::Duration::from_millis(backoff_ms)).await;                                             continue;                                         }                                         Err(e) => return Err(e),                                     }                                 }                             }                         }                         .await;                         (out_png.clone(), gif_dest.clone(), bytes_res)                     }                 };                  let res = match res {                     Ok(bytes) => {                         let out_png_for_job = out_png.clone();                         let _permit = limiter.acquire().await.ok();                         let job = handle.spawn_blocking(move || -> Result<egui::ColorImage> {                             use std::io::Cursor;                             use image::AnimationDecoder;                             use image::ImageEncoder;                             use image::DynamicImage;                              let decoder = image::codecs::gif::GifDecoder::new(Cursor::new(bytes))                                 .map_err(|err| anyhow!("failed to decode gif: {err}"))?;                             let mut frames = decoder.into_frames();                             let frame = frames                                 .next()                                 .ok_or_else(|| anyhow!("gif contained no frames"))?                                 .map_err(|err| anyhow!("failed to decode gif frame: {err}"))?;                                                                                       let dynamic_img = DynamicImage::ImageRgba8(frame.into_buffer());                             let rgba_buf = dynamic_img.to_rgba8();                              let color_image = egui::ColorImage::from_rgba_unmultiplied(                                 [rgba_buf.width() as usize, rgba_buf.height() as usize],                                 rgba_buf.as_raw(),                             );                              let mut out = Vec::new();                             let encoder = image::codecs::png::PngEncoder::new(&mut out);                             encoder                                 .write_image(                                     rgba_buf.as_raw(),                                     rgba_buf.width(),                                     rgba_buf.height(),                                     image::ExtendedColorType::Rgba8,                                 )                                 .map_err(|err| anyhow!("failed to encode gif preview png: {err}"))?;                               persistence::write_atomic_bytes(&out_png_for_job, &out)                                 .map_err(|err| anyhow!("failed to write gif preview: {err}"))?;                                                          Ok(color_image)                         });                         match job.await {                             Ok(inner) => inner,                             Err(err) => Err(anyhow!("gif preview join failed: {err}")),                         }                     }                     Err(err) => Err(err),                 };                  match res {                     Ok(image) => {                         let _ = tx.send(GifPreviewEvent::Ready { out_png, gif_dest, image });                     }                     Err(_err) => {                         let _ = tx.send(GifPreviewEvent::Failed { out_png });                     }                 }             });         }     }); }  fn spawn_gif_animation_worker(     runtime_services: &RuntimeServices,     mut rx: WorkerRx<GifAnimationRequest>,     tx: WorkerTx<GifAnimationEvent>, ) {     let client = runtime_services.http_client.clone();     let handle = runtime_services.handle();     let limiter = Arc::clone(&runtime_services.full_decode_limiter);      runtime_services.spawn(async move {         while let Some(request) = rx.recv().await {             let client = client.clone();             let handle = handle.clone();             let tx = tx.clone();             let limiter = limiter.clone();             tokio::spawn(async move {                 let (texture_key, res) = match &request {                     GifAnimationRequest::FromFile { src_path, texture_key } => {                         let bytes_res = tokio::fs::read(&src_path).await.map_err(|err| {                             anyhow!("failed to read gif file {}: {err}", src_path.display())                         });                         (texture_key.clone(), bytes_res)                     }                     GifAnimationRequest::FromUrl { url, texture_key } => {                         let cache_path = gif_anim_cache_path(url);                                                                           let bytes_res = async {                             if cache_path.exists() {                                 tokio::fs::read(&cache_path).await.map_err(|err| {                                     anyhow!("failed to read cached gif {}: {err}", cache_path.display())                                 })                             } else {                                                                  let mut retries = 0u32;                                 let max_retries = 3u32;                                 let bytes = loop {                                     match client.get(url.clone()).send().await {                                         Ok(response) => match response.error_for_status() {                                             Ok(resp) => match resp.bytes().await {                                                 Ok(bytes) => break bytes.to_vec(),                                                 Err(e) if retries < max_retries => {                                                     retries += 1;                                                     let backoff_ms = 100 * (2_u64.pow(retries - 1));                                                     tokio::time::sleep(std::time::Duration::from_millis(backoff_ms)).await;                                                     continue;                                                 }                                                 Err(e) => return Err(anyhow!("failed to read gif body for {url}: {e}")),                                             }                                             Err(e) => return Err(anyhow!("gif request failed for {url}: {e}")),                                         }                                         Err(e) if retries < max_retries => {                                             retries += 1;                                             let backoff_ms = 100 * (2_u64.pow(retries - 1));                                             tokio::time::sleep(std::time::Duration::from_millis(backoff_ms)).await;                                             continue;                                         }                                         Err(e) => return Err(anyhow!("failed to download gif {url}: {e}")),                                     }                                 };                                                                                                   let cache_path_clone = cache_path.clone();                                 let bytes_clone = bytes.clone();                                 tokio::spawn(async move {                                     let _ = persistence::write_atomic_bytes(&cache_path_clone, &bytes_clone);                                 });                                                                  Ok(bytes)                             }                         }                         .await;                         (texture_key.clone(), bytes_res)                     }                 };                  let res = match res {                     Ok(bytes) => {                         let _permit = limiter.acquire().await.ok();                         let job = handle.spawn_blocking(move || -> Result<GifAnimation> {                             use std::io::Cursor;                             use image::AnimationDecoder;                              let decoder = image::codecs::gif::GifDecoder::new(Cursor::new(bytes))                                 .map_err(|err| anyhow!("failed to decode gif: {err}"))?;                             let frames_iter = decoder.into_frames();                              let mut frames = Vec::new();                             for (frame_num, frame_result) in frames_iter.enumerate() {                                 let frame = frame_result                                     .map_err(|err| anyhow!("failed to decode gif frame {}: {err}", frame_num))?;                                                                                                   let delay = frame.delay();                                 let (numer, denom) = delay.numer_denom_ms();                                 let delay_ms = if denom > 0 {                                     (numer as u32 / denom as u32).max(10)                                 } else {                                     10                                  };                                                                   let dynamic_img = image::DynamicImage::ImageRgba8(frame.into_buffer());                                 let rgba_buf = dynamic_img.to_rgba8();                                                                  let color_image = egui::ColorImage::from_rgba_unmultiplied(                                     [rgba_buf.width() as usize, rgba_buf.height() as usize],                                     rgba_buf.as_raw(),                                 );                                  frames.push(GifAnimationFrame {                                     image: color_image,                                     delay_ms,                                 });                             }                              if frames.is_empty() {                                 return Err(anyhow!("gif contained no frames"));                             }                              Ok(GifAnimation { frames })                         });                         match job.await {                             Ok(inner) => inner,                             Err(err) => Err(anyhow!("gif animation join failed: {err}")),                         }                     }                     Err(err) => Err(err),                 };                  match res {                     Ok(animation) => {                         let _ = tx.send(GifAnimationEvent::Ready { texture_key, animation });                     }                     Err(err) => {                         let _ = tx.send(GifAnimationEvent::Failed {                             texture_key,                             error: format!("{err:#}"),                         });                     }                 }             });         }     }); }  fn spawn_local_mod_image_worker(     runtime_services: &RuntimeServices,     portable: PortablePaths,     global_generation: Arc<AtomicU64>,     cache_limit_bytes: Arc<AtomicU64>,     rx: WorkerRx<LocalModImageRequest>,     tx: WorkerTx<LocalModImageResult>, ) {     let rx = Arc::new(tokio::sync::Mutex::new(rx));     let handle = runtime_services.handle();     let thumb_limiter = Arc::clone(&runtime_services.thumb_image_limiter);     let full_limiter = Arc::clone(&runtime_services.full_image_limiter);     let full_decode_limiter = Arc::clone(&runtime_services.full_decode_limiter);     let thumbnail_byte_cache = runtime_services.thumbnail_byte_cache.clone();      for _ in 0..LOCAL_MOD_IMAGE_WORKERS {         let rx = Arc::clone(&rx);         let tx = tx.clone();         let portable = portable.clone();         let handle = handle.clone();         let thumb_limiter = Arc::clone(&thumb_limiter);         let cache_limit_bytes = Arc::clone(&cache_limit_bytes);         let global_generation = Arc::clone(&global_generation);         let full_limiter = Arc::clone(&full_limiter);         let full_decode_limiter = Arc::clone(&full_decode_limiter);         let thumbnail_byte_cache = thumbnail_byte_cache.clone();         runtime_services.spawn(async move {             loop {                 let request = {                     let mut guard = rx.lock().await;                     guard.recv().await                 };                 let Some(request) = request else {                     break;                 };                  if request.generation < global_generation.load(Ordering::Relaxed) {                     let _ = tx.send(LocalModImageResult {                         texture_key: request.texture_key,                         image_full: None,                         image_thumb: None,                         done: true,                         thumb_generated: false,                         thumb_meta: None,                     });                     continue;                 }                  let texture_key = request.texture_key.clone();                 match request.payload {                     LocalModImagePayload::Path { path, thumb_profile } => {                         let path_for_meta = path.clone();                         let (mtime, size) = handle.spawn_blocking(move || {                             fs::metadata(&path_for_meta).ok().map(|m| {                                 let mt = m.modified().ok()                                     .and_then(|t| t.duration_since(SystemTime::UNIX_EPOCH).ok())                                     .map(|d| d.as_secs())                                     .unwrap_or(0);                                 (mt, m.len())                             })                         }).await.ok().flatten().unwrap_or((0, 0));                          let path_str = path.to_string_lossy();                         let cache_key = format!("local_thumb:{}:{}:{}:{}", thumb_profile.suffix(), mtime, size, hash64_hex(path_str.as_bytes()));                         let portable_for_get = portable.clone();                                                                           if matches!(request.mode, LocalModImageMode::CardThumbOnly | LocalModImageMode::ThumbOnly) {                             if let Some(cached_bytes) = thumbnail_byte_cache.get(&cache_key) {                                 if let Some(image_thumb) = load_cover_color_image(cached_bytes.as_slice()) {                                     let _ = tx.send(LocalModImageResult {                                         texture_key: texture_key.clone(),                                         image_full: None,                                         image_thumb: Some(image_thumb),                                         done: true,                                         thumb_generated: false,                                         thumb_meta: None,                                     });                                     continue;                                 }                             }                             let cache_key_for_get = cache_key.clone();                             if let Ok(Ok(Some(cached_bytes))) = handle.spawn_blocking(move ||                                  persistence::cache_get(&portable_for_get, &cache_key_for_get)                             ).await {                                 thumbnail_byte_cache.insert(cache_key.clone(), cached_bytes.clone());                                 if let Some(image_thumb) = load_cover_color_image(&cached_bytes) {                                     let _ = tx.send(LocalModImageResult {                                         texture_key: texture_key.clone(),                                         image_full: None,                                         image_thumb: Some(image_thumb),                                         done: true,                                         thumb_generated: false,                                         thumb_meta: None,                                     });                                     continue;                                 }                             }                         };                                                   let path_for_io = path.clone();                          match request.mode {                             LocalModImageMode::CardThumbOnly | LocalModImageMode::ThumbOnly => {                                 let _thumb_permit = thumb_limiter.acquire().await.ok();                                 let decoded = handle                                     .spawn_blocking(move || {                                         let bytes = std::fs::read(&path_for_io).ok()?;                                         resize_image_bytes_to_thumbnail_rgba(&bytes, thumb_profile)                                     })                                     .await.ok().flatten();                                  if let Some((w, h, rgba)) = decoded {                                     let color_image = egui::ColorImage::from_rgba_unmultiplied([w as usize, h as usize], &rgba);                                                                          if let Ok(png_bytes) = resize_rgba_to_png(w, h, rgba) {                                         thumbnail_byte_cache.insert(cache_key.clone(), png_bytes.clone());                                         let portable_for_put = portable.clone();                                         let cache_key_for_put = cache_key.clone();                                         let limit = cache_limit_bytes.load(Ordering::Relaxed);                                         std::mem::drop(handle.spawn_blocking(move || {                                             persistence::cache_put(&portable_for_put, &cache_key_for_put, "local-thumb", &png_bytes, limit)                                         }));                                     }                                      let _ = tx.send(LocalModImageResult {                                         texture_key,                                         image_full: None,                                         image_thumb: Some(color_image),                                         done: true,                                         thumb_generated: false,                                         thumb_meta: None,                                     });                                 } else {                                     let _ = tx.send(LocalModImageResult { texture_key, image_full: None, image_thumb: None, done: true, thumb_generated: false, thumb_meta: None });                                 }                             }                             LocalModImageMode::FullOnly => {                                 let full_cache_key = format!("local_full:{}:{}:{}", mtime, size, hash64_hex(path_str.as_bytes()));                                 let portable_for_full_get = portable.clone();                                 let full_cache_key_for_get = full_cache_key.clone();                                 if let Ok(Ok(Some(cached_bytes))) = handle.spawn_blocking(move ||                                      persistence::cache_get(&portable_for_full_get, &full_cache_key_for_get)                                 ).await {                                     if let Some(image_full) = load_cover_color_image(&cached_bytes) {                                         let _ = tx.send(LocalModImageResult {                                             texture_key: texture_key.clone(),                                             image_full: Some(image_full),                                             image_thumb: None,                                             done: true,                                             thumb_generated: false,                                             thumb_meta: None,                                         });                                         continue;                                     }                                 };                                  let _full_permit = full_limiter.acquire().await.ok();                                 let _decode_permit = full_decode_limiter.acquire().await.ok();                                 let full = handle                                     .spawn_blocking(move || {                                         let bytes = std::fs::read(&path_for_io).ok()?;                                         load_cover_color_image(&bytes)                                     })                                     .await                                     .ok()                                     .flatten();                                  let mut image_thumb = None;                                 if let Some(image_full) = full.as_ref() {                                     let w = image_full.width() as u32;                                     let h = image_full.height() as u32;                                     let rgba: Vec<u8> = image_full.pixels.iter().flat_map(|c| [c.r(), c.g(), c.b(), c.a()]).collect();                                                                           if let Some((tw, th, trgba)) = resize_rgba_to_thumbnail_rgba(w, h, rgba.clone(), thumb_profile) {                                         image_thumb = Some(egui::ColorImage::from_rgba_unmultiplied([tw as usize, th as usize], &trgba));                                     }                                                                           if let Ok(png_bytes) = resize_rgba_to_png(w, h, rgba) {                                         let portable_for_put = portable.clone();                                         let cache_key_for_put = full_cache_key.clone();                                         let limit = cache_limit_bytes.load(Ordering::Relaxed);                                         std::mem::drop(handle.spawn_blocking(move || {                                             persistence::cache_put(&portable_for_put, &cache_key_for_put, "local-full", &png_bytes, limit)                                         }));                                     }                                 }                                  let _ = tx.send(LocalModImageResult {                                     texture_key,                                     image_full: full,                                     image_thumb,                                     done: true,                                     thumb_generated: false,                                     thumb_meta: None,                                 });                             }                         }                     }                     LocalModImagePayload::CardThumb {                         mod_root,                         source_path,                         source_url,                         expected_meta,                         force_regen,                     } => {                         let thumb_path =                             HestiaApp::resolve_mod_thumb_path(&mod_root, ThumbnailProfile::Card);                         let thumb_ram_key = format!("card-thumb:{texture_key}");                         let mut thumb_bytes = None;                         let mut generated = false;                          if !force_regen {                             thumb_bytes = thumbnail_byte_cache                                 .get(&thumb_ram_key)                                 .map(|bytes| bytes.as_ref().clone());                         }                          if thumb_bytes.is_none() && !force_regen && thumb_path.exists() {                             thumb_bytes = tokio::fs::read(&thumb_path).await.ok();                             if let Some(bytes) = thumb_bytes.as_ref() {                                 thumbnail_byte_cache.insert(thumb_ram_key.clone(), bytes.clone());                             }                         }                          if thumb_bytes.is_none() {                             let source_bytes = if let Some(path) = source_path {                                 tokio::fs::read(path).await.ok()                             } else if let Some(url) = source_url {                                 let cache_key = format!("img:{}", hash64_hex(url.as_bytes()));                                 persistence::cache_get(&portable, &cache_key).ok().flatten()                             } else {                                 None                             };                             if let Some(source_bytes) = source_bytes {                                 let encoded = handle                                     .spawn_blocking(move || {                                         resize_image_bytes_to_thumbnail_png(                                             &source_bytes,                                             ThumbnailProfile::Card,                                         )                                     })                                     .await                                     .ok()                                     .and_then(Result::ok);                                 if let Some(encoded) = encoded {                                     thumbnail_byte_cache.insert(thumb_ram_key.clone(), encoded.clone());                                     let thumb_path_for_write = thumb_path.clone();                                     let encoded_for_write = encoded.clone();                                     std::mem::drop(handle.spawn_blocking(move || {                                         let _ = persistence::write_atomic_bytes(&thumb_path_for_write, &encoded_for_write);                                     }));                                     thumb_bytes = Some(encoded);                                     generated = true;                                 }                             }                         }                          let image_thumb = thumb_bytes                             .as_deref()                             .and_then(load_cover_color_image);                         let _ = tx.send(LocalModImageResult {                             texture_key,                             image_full: None,                             image_thumb,                             done: true,                             thumb_generated: generated,                             thumb_meta: if generated { Some(expected_meta) } else { None },                         });                     }                 }             }         });     } }  fn spawn_cover_worker(     runtime_services: &RuntimeServices,     mut rx: WorkerRx<CoverRequest>,     tx: WorkerTx<CoverResult>, ) {     runtime_services.spawn(async move {         while let Some(request) = rx.recv().await {             let Some(bytes) = game_cover_bytes(&request.game_id) else {                 continue;             };             let Some(image) = load_cover_color_image(bytes) else {                 continue;             };             let _ = tx.send(CoverResult {                 game_id: request.game_id,                 image,             });         }     }); } 

fn is_timeout_error(err: &anyhow::Error) -> bool {     if err         .chain()         .filter_map(|cause| cause.downcast_ref::<reqwest::Error>())         .any(reqwest::Error::is_timeout)     {         return true;     }      let lowered = format!("{err:#}").to_lowercase();     lowered.contains("timed out") || lowered.contains("timeout") }  fn resize_rgba_to_png(w: u32, h: u32, rgba: Vec<u8>) -> Result<Vec<u8>> {     let mut out = Vec::new();     {         use image::ImageEncoder;         let encoder = image::codecs::png::PngEncoder::new(&mut out);         encoder.write_image(&rgba, w, h, image::ExtendedColorType::Rgba8)?;     }     Ok(out) }  fn load_cover_texture(     ctx: &egui::Context,     bytes: &[u8],     texture_name: &str, ) -> Option<egui::TextureHandle> {     let image = load_cover_color_image(bytes)?;     Some(ctx.load_texture(         texture_name,         image,         egui::TextureOptions::LINEAR,     )) }  fn load_image_texture(     ctx: &egui::Context,     bytes: &[u8],     texture_name: &str, ) -> Option<egui::TextureHandle> {     let image = load_cover_color_image(bytes)?;     Some(ctx.load_texture(         texture_name,         image,         egui::TextureOptions::LINEAR,     )) }  fn load_cover_color_image(bytes: &[u8]) -> Option<egui::ColorImage> {     let image = image::ImageReader::new(std::io::Cursor::new(bytes))         .with_guessed_format()         .ok()?         .decode()         .ok()?         .into_rgba8();     let width = image.width() as usize;     let height = image.height() as usize;     if width == 0 || height == 0 {         return None;     }      let pixels = image.into_raw();     let color_image = egui::ColorImage::from_rgba_unmultiplied([width, height], &pixels);     Some(color_image) }   fn load_cover_color_image_thumbnail(bytes: &[u8], profile: ThumbnailProfile) -> Option<egui::ColorImage> {     resize_image_bytes_to_thumbnail_rgba(bytes, profile).and_then(|(w, h, rgba)| {         let width = usize::try_from(w).ok()?;         let height = usize::try_from(h).ok()?;         Some(egui::ColorImage::from_rgba_unmultiplied([width, height], &rgba))     }) }  fn resize_image_bytes_to_thumbnail_png(bytes: &[u8], profile: ThumbnailProfile) -> Result<Vec<u8>> {     let Some((w, h, rgba)) = resize_image_bytes_to_thumbnail_rgba(bytes, profile) else {         bail!("failed to generate thumbnail");     };     let mut out = Vec::new();     {         use image::ImageEncoder;         let encoder = image::codecs::png::PngEncoder::new(&mut out);         encoder.write_image(&rgba, w, h, image::ExtendedColorType::Rgba8)?;     }     Ok(out) }  fn resize_image_bytes_to_thumbnail_rgba(     bytes: &[u8],     profile: ThumbnailProfile, ) -> Option<(u32, u32, Vec<u8>)> {     let image = image::ImageReader::new(std::io::Cursor::new(bytes))         .with_guessed_format()         .ok()?         .decode()         .ok()?         .into_rgba8();      let src_w = image.width();     let src_h = image.height();     let raw = image.into_raw();      resize_rgba_to_thumbnail_rgba(src_w, src_h, raw, profile) }  fn resize_rgba_to_thumbnail_rgba(     src_w: u32,     src_h: u32,     rgba: Vec<u8>,     profile: ThumbnailProfile, ) -> Option<(u32, u32, Vec<u8>)> {     if src_w == 0 || src_h == 0 {         return None;     }      let (target_w, target_h) = profile.dimensions();     if src_w <= target_w && src_h <= target_h {         return Some((src_w, src_h, rgba));     }      let scale = (target_w as f32 / src_w as f32)         .min(target_h as f32 / src_h as f32)         .min(1.0);     let dst_w = ((src_w as f32 * scale).round().max(1.0)) as u32;     let dst_h = ((src_h as f32 * scale).round().max(1.0)) as u32;      let mut src_image = fir::images::Image::from_vec_u8(         src_w,         src_h,         rgba,         fir::PixelType::U8x4,     ).ok()?;     let mut dst_image = fir::images::Image::new(dst_w, dst_h, fir::PixelType::U8x4);      thread_local! {         static RESIZER: std::cell::RefCell<fir::Resizer> =             std::cell::RefCell::new(fir::Resizer::new());     }           let options = fir::ResizeOptions::new();      let success = RESIZER.with(|r| {         r.borrow_mut().resize(&mut src_image, &mut dst_image, &options).is_ok()     });      if success {         Some((dst_w, dst_h, dst_image.into_vec()))     } else {         None     } }   fn load_title_icon_texture(     ctx: &egui::Context,     bytes: &[u8],     texture_name: &str, ) -> Option<egui::TextureHandle> {     let image = load_icon_color_image(bytes)?;     Some(ctx.load_texture(         texture_name,         image,         egui::TextureOptions::LINEAR,     )) }  fn load_icon_color_image(bytes: &[u8]) -> Option<egui::ColorImage> {     let image = image::load_from_memory(bytes).ok()?.to_rgba8();     let resized = image::imageops::resize(         &image,         GAME_ICON_TEXTURE_SIZE,         GAME_ICON_TEXTURE_SIZE,         image::imageops::FilterType::Triangle,     );     let width = usize::try_from(resized.width()).ok()?;     let height = usize::try_from(resized.height()).ok()?;     let pixels = resized.as_flat_samples();     let color_image = egui::ColorImage::from_rgba_unmultiplied([width, height], pixels.as_slice());     Some(color_image) } 
